mapper.select:
SELECT DATE(order_time) AS date, SUM(total_amount) AS revenue, COUNT(*) AS orderCount FROM t_sales_order WHERE tenant_id = #{tenantId} AND deleted = 0 AND order_time >= #{startDate} AND order_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)
AND store_id = #{storeId}
GROUP BY DATE(order_time) ORDER BY date

SELECT soi.dish_id AS dishId, soi.dish_name AS dishName, SUM(soi.quantity) AS quantity, SUM(soi.subtotal) AS revenue FROM t_sales_order_item soi INNER JOIN t_sales_order so ON soi.order_id = so.id WHERE so.tenant_id = #{tenantId} AND so.deleted = 0 AND soi.deleted = 0 AND so.order_time >= #{startDate} AND so.order_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)
AND so.store_id = #{storeId}
GROUP BY soi.dish_id, soi.dish_name ORDER BY quantity DESC LIMIT #{topN}
